UPDATE rca.tb_syslog_alarm_mst
SET status = 'AUTO_FIN'
WHERE status NOT IN ('FIN')
  AND node_num = #{nodeNum}
  AND node_nm = #{nodeNm}
  and alarmmsg like '%IFMGR_IF%'

